import React, { useEffect, useState } from "react";

const TicketHistory = ({ employee }) => {
  const [ticketData, setTicketData] = useState([]);
  const [fromDate, setFrom] = useState("");
  const [toDate, setTo] = useState("");

  useEffect(() => {
    if (employee?.empId || employee?.empld) fetchData();
  }, [employee]);

  const fetchData = async () => {
    try {
      const empId = employee.empId || employee.empld;

      const response = await fetch(
        `https://prasa-app-yde3.onrender.com/ticket-expenses?empId=${empId}`
      );

      const data = await response.json();
      setTicketData(Array.isArray(data) ? data : []);
    } catch (err) {
      console.error(err);
      setTicketData([]);
    }
  };

  const filtered = ticketData.filter((t) => {
    const d = new Date(t.ticket_date);
    const f = fromDate ? new Date(fromDate) : null;
    const to = toDate ? new Date(toDate) : null;

    if (f && d < f) return false;
    if (to && d > to) return false;
    return true;
  });

  const downloadReport = () => {
    alert("Downloading Monthly Ticket Report…");
  };

  return (
    <div style={page}>
      <div style={headerCard}>
        <button onClick={() => window.history.back()} style={backBtn}>←</button>
        <h2 style={headerTitle}>Ticket Expense History</h2>
        <p style={empInfo}>{employee.empName} • {employee.empId}</p>
      </div>

      <div style={filterCard}>
        <div style={filterItem}>
          <label style={label}>From Date</label>
          <input type="date" value={fromDate} onChange={(e)=>setFrom(e.target.value)} style={inputBox}/>
        </div>

        <div style={filterItem}>
          <label style={label}>To Date</label>
          <input type="date" value={toDate} onChange={(e)=>setTo(e.target.value)} style={inputBox}/>
        </div>

        <button onClick={fetchData} style={resetBtn}>Reset</button>
      </div>

      <table style={table}>
        <thead>
          <tr>
            <th>Date</th>
            <th>Purpose</th>
            <th>Assigned To</th>
            <th>Amount</th>
          </tr>
        </thead>

        <tbody>
          {filtered.length === 0 ? (
            <tr><td colSpan="4" style={emptyText}>No records found</td></tr>
          ) : (
            filtered.map((t) => (
              <tr key={t.id}>
                <td>{t.ticket_date}</td>
                <td>{t.purpose}</td>
                <td>{t.assigned_to}</td>
                <td>₹ {t.amount}</td>
              </tr>
            ))
          )}
        </tbody>
      </table>

      <div style={downloadContainer}>
        <button style={downloadBtn} onClick={downloadReport}>
          📄 Download Monthly Report
        </button>
      </div>
    </div>
  );
};

export default TicketHistory;

/* SAME UI STYLES FROM TRAVEL HISTORY */
const green = "#0F9D58";

const page = { padding: 20, background: "#F1F8F2", minHeight: "100vh" };
const headerCard = { background:"#fff",padding:18,borderRadius:15,boxShadow:"0 3px 10px rgba(0,0,0,0.1)",marginBottom:15 };
const backBtn = { background:"#fff",border:`1px solid ${green}`,color:green,borderRadius:10,padding:"6px 12px",fontSize:20,cursor:"pointer" };
const headerTitle = { marginTop:10,fontSize:24,color:green,fontWeight:"700" };
const empInfo = { color:"#666",marginTop:-5,fontSize:14 };
const filterCard = { display:"flex",gap:15,background:"#E8F5E9",padding:15,borderRadius:12,marginBottom:20 };
const filterItem = { flex:1 };
const label = { fontWeight:"600",marginBottom:5 };
const inputBox = { width:"100%",padding:10,borderRadius:10,border:"1px solid #ccc" };
const resetBtn = { background:green,color:"#fff",padding:"10px 18px",borderRadius:10,border:"none",cursor:"pointer",height:42,marginTop:20 };
const table = { width:"100%",background:"white",borderRadius:14,padding:10,boxShadow:"0 2px 8px rgba(0,0,0,0.08)" };
const emptyText = { textAlign:"center",padding:20,color:"#999" };
const downloadContainer = { marginTop: 20, textAlign: "left" };
const downloadBtn = { background:green,color:"white",padding:"12px 20px",borderRadius:10,border:"none",cursor:"pointer",fontSize:16,fontWeight:"600" };
